insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:4-3-sales-process-customer-service:tf:62073e4c', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "A business with a well-designed website will always provide better customer engagement than a physical shop."}'::jsonb, '{"answer": false, "explain": "FALSE. A website creates a professional image, but customer engagement — the contact between business and customer — is often stronger in face-to-face settings where staff can directly answer questions, demonstrate products, and build personal relationships."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:d1113c4a', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Click and collect has meant that businesses need to dedicate more in-store space for collection points."}'::jsonb, '{"answer": true, "explain": "TRUE. The success of click and collect has led businesses to allocate dedicated floor space for collection customers inside their stores, affecting how the available space is used overall."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:7df1ce1a', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "E-commerce always reduces the number of employees a business needs."}'::jsonb, '{"answer": false, "explain": "FALSE. The effect on employment depends on the situation. An existing business switching to e-commerce may reduce staff in branches. But a new e-commerce business must recruit warehouse staff, website managers, and customer service representatives."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:adcbe72e', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Online security is only a concern for customers, not for businesses using e-commerce."}'::jsonb, '{"answer": false, "explain": "FALSE. Security is a concern for BOTH customers AND businesses. Businesses must operate a secure website and keep customer data safe. A security breach damages customer trust and can result in significant financial costs and reputational harm."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:2656ae09', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Product knowledge is equally important in all types of businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. The importance of product knowledge varies by context. It is highly important in electronics stores or garden centres where customers need expert advice. It is relatively less critical in, for example, a newsagent."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:f921101d', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Amazon focuses more on pricing, choice, and speed of delivery than on face-to-face customer engagement."}'::jsonb, '{"answer": true, "explain": "TRUE. Amazon competes primarily through price, product range, and delivery speed (Amazon Prime). John Lewis, by contrast, relies on face-to-face customer engagement and product knowledge in its stores."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:7a4c9340', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Cold calling (unsolicited telesales) is generally viewed positively by customers."}'::jsonb, '{"answer": false, "explain": "FALSE. Cold calling is widely seen as a nuisance by many customers, particularly when calls arrive at inconvenient times. This is a growing issue with telesales as a selling method."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:b64eb83c', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "E-commerce can help a small business compete with much larger firms on a global scale."}'::jsonb, '{"answer": true, "explain": "TRUE. E-commerce allows even the smallest business to reach a worldwide market with a professional-looking website at relatively low cost — competing on a scale that would not have been possible through traditional retail."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:9efa567d', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must know for 4.3. Learn them precisely — examiners reward specific, accurate definitions.</p>\n<ul>\n<li><strong>E-commerce:</strong> The bringing together of buying and selling electronically (online sales).</li>\n<li><strong>Customer service:</strong> The name given to an area of business that deals with customer enquiries.</li>\n<li><strong>Customer engagement:</strong> The contact between the business and customer.</li>\n<li><strong>Click and collect:</strong> Ordering online and collecting goods from store at a later time.</li>\n<li><strong>Face to face selling:</strong> Usually completed in a shop where there is direct contact between buyer and seller.</li>\n<li><strong>Telesales:</strong> Sales completed over the telephone.</li>\n<li><strong>After-sales service:</strong> Advice and help given to a customer after they have bought a product or service.</li>\n<li><strong>Product knowledge:</strong> The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.</li>\n</ul>", "question": "According to the key terms, what is ''customer engagement''?", "options": ["Direct contact between buyer and seller in a shop", "The contact between the business and customer", "The area of business dealing with customer enquiries", "Advice given to a customer after a purchase"]}'::jsonb, '{"answer": 1, "explain": "Customer engagement is defined precisely as ''the contact between the business and customer'' — distinct from customer service (enquiries) or after-sales service (post-purchase advice)."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:2c187692', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Methods of Selling", "reading": "<p>Businesses can use a range of selling methods depending on the product, target market, and business size. The three main methods are:</p>\n<ul>\n<li><strong>E-commerce:</strong> Bringing a buyer and seller together electronically. Involves physical delivery after an online sale.</li>\n<li><strong>Face to face:</strong> Direct contact between buyer and seller, typically in a shop, bank, or travel agent. Allows advice and interaction.</li>\n<li><strong>Telesales:</strong> Sales completed over the telephone. Acts as a bridge between e-commerce and face to face, especially useful for customers less comfortable with the internet.</li>\n</ul>\n<p>Not all businesses are suited to every method. The best method depends on the <strong>product type</strong>, the <strong>target market</strong>, and the level of <strong>service</strong> required.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: John Lewis & Partners</h4>\n<p>John Lewis uses all three methods. Its department stores use face-to-face selling with trained staff who have excellent product knowledge, particularly in electronics. It also has a fast-growing e-commerce operation and uses phone lines for customer queries. JLP''s strategy shows how a business can combine multiple selling methods to serve different customers effectively.</p>\n</div>", "question": "Which company, according to the case study, uses all three selling methods (face-to-face, e-commerce, and telesales)?", "options": ["Marks & Spencer", "JC Motors Ltd", "Amazon UK Ltd", "John Lewis Partners"]}'::jsonb, '{"answer": 3, "explain": "The case study states John Lewis uses face-to-face selling in stores, a fast-growing e-commerce operation, and phone lines for customer queries."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:611b30b5', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "The Influence of E-commerce on Business Activity", "reading": "<p>The growth of e-commerce — accelerated dramatically during the COVID-19 pandemic of 2020–21 — has changed business activity in several key ways:</p>\n<ul>\n<li><strong>Location:</strong> Businesses can locate almost anywhere. A telephone/internet connection handles the \"front end\" (orders), while warehouses can be separately sited near motorway networks for fast delivery.</li>\n<li><strong>New skill development:</strong> Staff need new skills — website maintenance, email responses, warehouse packing. Extra training may be required at all levels.</li>\n<li><strong>Levels of employment:</strong> E-commerce may increase OR decrease employment. Existing businesses may need fewer branch staff (e.g. banks), but new e-commerce startups must recruit website, logistics, and customer service staff.</li>\n<li><strong>Creation of specific departments:</strong> Large businesses like M&S, Next, and John Lewis have set up dedicated online departments to manage e-commerce sales and avoid losing business to competitors.</li>\n<li><strong>Click and collect:</strong> Customers order online and collect in-store later, solving the \"not home for delivery\" problem. Stores must dedicate space for click and collect areas.</li>\n<li><strong>Delivery options:</strong> Speed of delivery is a key competitive area. Amazon Prime offers next-day and same-day delivery. Drone delivery is a future possibility but faces security and safety hurdles.</li>\n</ul>", "question": "What historic event is identified as dramatically accelerating e-commerce growth?", "options": ["The COVID-19 pandemic of 2020–21", "The launch of Amazon Prime", "The 2008 financial crisis", "The invention of the smartphone"]}'::jsonb, '{"answer": 0, "explain": "The card states the growth of e-commerce was ''accelerated dramatically during the COVID-19 pandemic of 2020–21''."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:efa9b50a', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of E-commerce for Businesses", "reading": "<p>When evaluating e-commerce, always check whether the question asks for the <strong>business''s</strong> perspective or the <strong>customer''s</strong> perspective. Mixing these up is one of the most common reasons students lose marks.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages for Businesses</div>\n<div class=\"pro-item\"><strong>Sell worldwide:</strong> Even the smallest business can reach a global market, significantly increasing the potential customer base, sales, and profit.</div>\n<div class=\"pro-item\"><strong>Open all the time:</strong> No restriction on opening hours — the business can generate sales 24 hours a day, 7 days a week.</div>\n<div class=\"pro-item\"><strong>Professional look at little cost:</strong> A well-designed website creates a strong brand image, attracting customers without the need for expensive premises.</div>\n<div class=\"pro-item\"><strong>Lower operating costs:</strong> No need to pay expensive city-centre rents. The business can operate from anywhere with an internet connection, keeping profits high.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages for Businesses</div>\n<div class=\"con-item\"><strong>Worldwide competition:</strong> All e-commerce businesses face global competitors. Customers can easily compare prices, putting downward pressure on margins.</div>\n<div class=\"con-item\"><strong>Problems of delivering goods and accepting returns:</strong> Reliance on third-party logistics adds cost. High return rates increase expenses further.</div>\n<div class=\"con-item\"><strong>Online security:</strong> Businesses must maintain a secure website and keep customer data safe. A breach destroys customer trust and adds significant costs.</div>\n<div class=\"con-item\"><strong>Advances in technology:</strong> Businesses must constantly update their technology (e.g. mobile-optimised sites) to keep up with customer buying habits. This is ongoing and costly.</div>\n</div>\n</div>", "question": "Which of these is listed as a disadvantage of e-commerce FOR BUSINESSES (not customers)?", "options": ["Restricted shop opening hours", "Customers cannot touch or try products before buying", "Payment is geared towards card/debit only", "Worldwide competition puts downward pressure on margins"]}'::jsonb, '{"answer": 3, "explain": "The business disadvantages list worldwide competition and easy price comparison putting downward pressure on margins; the other options are customer-side issues."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:0a2a3856', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of E-commerce for Customers", "reading": "<p>Customers experience both benefits and drawbacks from e-commerce. Remember — some exam questions specifically ask about the <strong>customer''s</strong> perspective, not the business''s.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages for Customers</div>\n<div class=\"pro-item\"><strong>Price comparison:</strong> Customers can easily compare prices across multiple sites, getting the best deal and saving money.</div>\n<div class=\"pro-item\"><strong>Seven-day availability:</strong> Customers can buy at any time convenient to them — not restricted to shop opening hours.</div>\n<div class=\"pro-item\"><strong>Wide range of products:</strong> The internet provides worldwide access, giving customers far greater choice than any single physical store could offer.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages for Customers</div>\n<div class=\"con-item\"><strong>Lack of personal contact:</strong> No person to talk to directly, which may deter some customers — especially for complex or expensive purchases.</div>\n<div class=\"con-item\"><strong>Security risk:</strong> Customers worry about credit card and personal data being stolen, even with encryption available.</div>\n<div class=\"con-item\"><strong>Methods of payment:</strong> Customers who prefer cash cannot use e-commerce, as payment is geared towards credit/debit cards.</div>\n<div class=\"con-item\"><strong>Technology barriers:</strong> Some customers (especially older groups) lack internet access or confidence with technology.</div>\n<div class=\"con-item\"><strong>Only images seen:</strong> Cannot touch, feel, or try products before buying. This is less of a problem for familiar products (e.g. a known DVD) but significant for clothing or furniture.</div>\n</div>\n</div>", "question": "Which is listed as a disadvantage of e-commerce FOR CUSTOMERS?", "options": ["Businesses must constantly update their technology to stay competitive", "Businesses face worldwide competition from other online sellers", "Businesses must maintain secure websites to protect customer data", "They cannot touch, feel, or try products before buying"]}'::jsonb, '{"answer": 3, "explain": "''Only images seen'' — being unable to touch, feel, or try products — is listed as a customer disadvantage; the other options are business-side disadvantages."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:261483d2', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Face to Face Selling & Telesales", "reading": "<p><strong>Face to face selling</strong> is typically done in a shop, bank, or travel agent. Key features:</p>\n<ul>\n<li>Direct interaction allows advice, demonstrations, questions, and answers</li>\n<li>Customers can see and handle products before buying</li>\n<li>Builds trust and personal relationships, encouraging return visits</li>\n<li>However, shops are <strong>expensive to operate</strong> — staff wages, rent, local taxes, cleaning and maintenance all apply</li>\n<li>Poor weather or inconvenience may push customers to shop online instead</li>\n</ul>\n<p><strong>Telesales</strong> bridges e-commerce and face to face. Key features:</p>\n<ul>\n<li>Useful for customers not comfortable with online shopping but happy to talk by phone</li>\n<li>Allows the customer to negotiate — e.g. renewing a mobile phone contract by phone lets them bargain for a better deal</li>\n<li>Larger businesses have dedicated telesales departments; smaller businesses may lack staff</li>\n<li><strong>Cold calling</strong> — unsolicited calls at inconvenient times — is seen as a nuisance by many customers</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Best for Face to Face</div>\n<div class=\"pro-item\">High-value or complex products (e.g. cars, wedding dresses, electronics)</div>\n<div class=\"pro-item\">When service and advice are central to the buying decision</div>\n<div class=\"pro-item\">When customers want to touch or try the product before buying</div>\n</div>\n<div>\n<div class=\"col-head\">✓ Best for Telesales</div>\n<div class=\"con-item\">Renewing subscriptions or contracts (e.g. insurance, phone, utilities)</div>\n<div class=\"con-item\">Reaching customers who are not tech-savvy</div>\n<div class=\"con-item\">When customers want to negotiate terms or receive personalised guidance by phone</div>\n</div>\n</div>", "question": "Which selling method is most useful for a customer who wants to negotiate a better deal, e.g. renewing a mobile phone contract?", "options": ["E-commerce", "Face to face selling", "Click and collect", "Telesales"]}'::jsonb, '{"answer": 3, "explain": "The card states telesales allows the customer to negotiate — e.g. renewing a mobile phone contract by phone lets them bargain for a better deal."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:208ae89a', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "The Importance of Customer Service & After-Sales Service", "reading": "<p><strong>Customer service</strong> is vital to maintaining and increasing sales. A business must retain existing customers and attract new ones — losing customers to competitors is extremely costly.</p>\n<p>Good customer service is especially important where the product requires a high level of service — compare buying a book online (low service needed) with buying a wedding dress (high service, face-to-face essential).</p>\n<p><strong>After-sales service</strong> is what happens when things go wrong after a purchase. It might include:</p>\n<ul>\n<li>Offering refunds or exchanges (even where not legally required)</li>\n<li>Organising speedy repairs</li>\n<li>Keeping the customer informed about a problem being resolved</li>\n</ul>\n<p>The goal is to leave the customer satisfied, so they return and spend more in the future. Competitors are always ready to take customers from any business seen to be falling short on service.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Why After-Sales Service Matters</div>\n<div class=\"pro-item\">Ensures customers are satisfied after purchase, encouraging repeat business and loyalty.</div>\n<div class=\"pro-item\">Builds trust — customers who experience good problem resolution are more likely to return.</div>\n<div class=\"pro-item\">Positive word-of-mouth — satisfied customers recommend the business, attracting new customers at no extra marketing cost.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Risks of Poor After-Sales Service</div>\n<div class=\"con-item\">Customers switch to competitors after a bad post-purchase experience.</div>\n<div class=\"con-item\">Negative online reviews can rapidly damage brand reputation in the e-commerce age.</div>\n<div class=\"con-item\">Lost sales and reduced market share in the long run.</div>\n</div>\n</div>", "question": "Which purchase is used as the example of a product needing HIGH customer service, where face-to-face is essential?", "options": ["A wedding dress", "A DVD", "A phone contract renewal", "A book"]}'::jsonb, '{"answer": 0, "explain": "The card contrasts buying a book online (low service needed) with buying a wedding dress (high service, face-to-face essential)."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:c295d646', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Product Knowledge & Customer Engagement", "reading": "<p><strong>Product knowledge</strong> is the detailed understanding staff have about what they sell. Its importance varies by business type:</p>\n<ul>\n<li>In a <strong>garden centre</strong>, staff need to advise on plants for specific conditions.</li>\n<li>In an <strong>electronics store</strong>, staff need to explain the latest TV or laptop technology to less-informed customers.</li>\n<li>In a <strong>newsagent</strong>, product knowledge is relatively less critical.</li>\n</ul>\n<p>Training costs time and money, but better product knowledge &rarr; better customer service &rarr; more sales &rarr; profits cover the cost of training.</p>\n<p><strong>Customer engagement</strong> is the contact between a customer and the business. Good engagement means:</p>\n<ul>\n<li>Well-trained, polite, knowledgeable staff in face-to-face settings</li>\n<li>A friendly, helpful voice in telesales</li>\n<li>Carefully worded emails and texts in e-commerce (replicating the feeling of face-to-face engagement)</li>\n</ul>\n<p>⚠️ There is a fine line between being helpful and being too \"pushy.\" Car salespeople have a reputation for over-engagement — too much information or pressure can drive customers away.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: Amazon vs John Lewis</h4>\n<p>Amazon competes on <strong>price, choice, and speed of delivery</strong> — using Prime''s next-day and same-day delivery to stay ahead. John Lewis, by contrast, focuses on <strong>product knowledge and face-to-face customer engagement</strong>, especially important for complex electronics purchases where customers need explanation. Both approaches show that excellent customer service can take very different forms depending on the business model.</p>\n</div>", "question": "In which type of business does the guide say product knowledge is ''relatively less critical''?", "options": ["A car dealership", "An electronics store", "A newsagent", "A garden centre"]}'::jsonb, '{"answer": 2, "explain": "The guide states that in a newsagent, product knowledge is relatively less critical, unlike a garden centre or electronics store."}'::jsonb),
('business:4-3-sales-process-customer-service:learn:0c3b3528', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Real-World Application: Amazon & E-commerce Growth", "reading": "<div class=\"case-study-box\">\n<h4>Case Study: Amazon</h4>\n<p>Amazon was started by Jeff Bezos in 1994, initially selling books online. It later expanded into electronics, video games, and through Amazon Marketplace, an enormous range of products. It is now one of the world''s leading e-commerce businesses.</p>\n<p>Amazon has always responded to competitors by focusing on speed and enhanced service. In 2007 it launched its <strong>Prime service</strong> in the UK, promising next-day delivery. When competitors matched this, Amazon added \"extras\" — free music and video streaming, same-day food delivery through Morrisons, and exclusive \"Prime Day\" deals for subscribers.</p>\n<p>Prime is a subscription service, and consumers are willing to pay for this enhanced level of service. Amazon places great emphasis on <strong>pricing, choice, and speed of delivery</strong> rather than face-to-face customer engagement.</p>\n</div>\n<p><strong>Key takeaways for the exam:</strong></p>\n<ul>\n<li>Amazon is an e-commerce business because it brings buyers and sellers together digitally, with physical delivery following the online sale</li>\n<li>It competes through speed and choice rather than in-person customer engagement</li>\n<li>Its success is closely tied to the logistics industry (warehouses, delivery networks)</li>\n<li>The coronavirus pandemic of 2020–21 accelerated e-commerce growth, forcing many traditional retailers to adapt or close (e.g. Debenhams and Top Shop left the high street)</li>\n</ul>", "question": "In what year did Amazon launch its Prime service in the UK?", "options": ["2015", "2020", "2007", "1994"]}'::jsonb, '{"answer": 2, "explain": "The case study states ''In 2007 it launched its Prime service in the UK, promising next-day delivery.''"}'::jsonb),
('business:4-3-sales-process-customer-service:misc:477ec19f', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Having a website means a business is doing e-commerce.</p><p><strong>✅ The correct idea:</strong> E-commerce means the business actually SELLS products online — not just advertises them. A business with only a promotional website that does not take online orders is NOT an e-commerce business.</p>", "question": "A business has a website that only advertises its products, with no way to buy online. Is this e-commerce?", "options": ["Yes – any business website automatically counts as e-commerce", "No – e-commerce requires actually selling online, not advertising", "Only if it''s a well-known brand with a large customer base", "Yes, as long as the website clearly lists prices and products"]}'::jsonb, '{"answer": 1, "explain": "E-commerce means the business actually sells online — a promotional-only website with no orders taken is not e-commerce."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:97b4848c', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> E-commerce is only suitable for large businesses like Amazon.</p><p><strong>✅ The correct idea:</strong> E-commerce is accessible to businesses of all sizes. A small business can set up a website for relatively little cost and reach a worldwide market, competing with larger firms in ways that were not possible before the internet.</p>", "question": "Which statement about e-commerce and business size is correct?", "options": ["E-commerce requires a large marketing budget to work at all", "Small businesses can use e-commerce to reach a worldwide market", "Only businesses with physical stores can succeed online", "E-commerce is only suitable for large businesses like Amazon"]}'::jsonb, '{"answer": 1, "explain": "E-commerce is accessible to businesses of all sizes — a small business can set up a website cheaply and reach a worldwide market."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:03f6c93a', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Customer service only means being polite to customers in a shop.</p><p><strong>✅ The correct idea:</strong> Customer service covers the FULL customer journey: before, during, AND after the sale. After-sales service (handling returns, repairs, complaints) is a critical and separately examinable component of good customer service.</p>", "question": "What does ''customer service'' actually cover, according to the guide?", "options": ["Only advertising and promotion before the sale is made", "Only handling complaints and returns after the sale is made", "Only being polite to customers face-to-face in a shop", "The full journey — before, during, and after the sale"]}'::jsonb, '{"answer": 3, "explain": "Customer service covers the full customer journey, including after-sales service, not just politeness in a shop."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:6644e168', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> E-commerce always reduces costs for a business.</p><p><strong>✅ The correct idea:</strong> While e-commerce can lower operating costs (no shop rent), it also creates NEW costs: website security, delivery logistics, returns handling, and keeping up with technology. The net financial effect depends on the specific business.</p>", "question": "Does e-commerce always reduce a business''s costs?", "options": ["No – it lowers some costs but adds new ones like security and logistics", "No – e-commerce always increases a business''s total operating costs", "Yes – it always reduces costs because there is no shop rent to pay", "Yes – because online businesses no longer need to employ any staff"]}'::jsonb, '{"answer": 0, "explain": "E-commerce can lower operating costs but also creates new costs such as website security, delivery logistics, and returns handling."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:a14acc70', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A disadvantage of e-commerce to the customer is that it costs the business more money.</p><p><strong>✅ The correct idea:</strong> When a question asks for a disadvantage to the CUSTOMER, you must write about how the customer is negatively affected — not how the business is affected. Mixing up perspectives is one of the most common ways students lose marks.</p>", "question": "If a question asks for a disadvantage of e-commerce TO THE CUSTOMER, what must the answer focus on?", "options": ["How the customer is negatively affected", "How the business loses market share", "How the business''s costs increase", "How delivery companies are affected"]}'::jsonb, '{"answer": 0, "explain": "Mixing up perspectives is a common error — an answer about a ''disadvantage to the customer'' must focus on the customer, not the business."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:cac16845', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Good customer engagement means being as helpful and informative as possible at all times.</p><p><strong>✅ The correct idea:</strong> There is a fine line between being helpful and being ''pushy.'' Too much information or pressure can drive customers away. Good engagement means reading the customer''s needs and responding appropriately — not overwhelming them.</p>", "question": "According to the guide, what is the risk of ''too much'' customer engagement?", "options": ["It only affects online customers, not face-to-face ones", "It always increases sales no matter how it''s done", "It has no downsides at all for the business", "It can feel pushy and drive customers away"]}'::jsonb, '{"answer": 3, "explain": "There is a fine line between being helpful and being pushy — too much information or pressure can drive customers away."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:ab9d2b71', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Product knowledge is only important for face-to-face selling.</p><p><strong>✅ The correct idea:</strong> Product knowledge is also important in telesales (staff must advise customers over the phone) and e-commerce (website descriptions, FAQs, and live chat all require accurate, detailed product information).</p>", "question": "Is product knowledge only important for face-to-face selling?", "options": ["No – it also matters in telesales and in e-commerce websites", "No – it only matters for e-commerce, not telesales", "Yes – it is completely irrelevant to telesales and e-commerce", "Yes – only face-to-face shop staff need product knowledge"]}'::jsonb, '{"answer": 0, "explain": "Product knowledge also matters in telesales (advising by phone) and e-commerce (accurate website descriptions and live chat)."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:f4420db2', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Click and collect is the same as home delivery.</p><p><strong>✅ The correct idea:</strong> Click and collect means the customer orders online but COLLECTS from a store — there is NO home delivery. It is specifically designed to solve the problem of customers not being home when a delivery arrives.</p>", "question": "What is the key difference between click and collect and home delivery?", "options": ["Click and collect only works for food and grocery shopping", "They are exactly the same thing with no real difference", "Click and collect is always faster than home delivery", "Click and collect means collecting from a store, not delivery"]}'::jsonb, '{"answer": 3, "explain": "Click and collect means ordering online but collecting from a store — there is no home delivery involved."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:7e5424e1', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> E-commerce and digital distribution mean the same thing.</p><p><strong>✅ The correct idea:</strong> E-commerce involves an online sale followed by PHYSICAL delivery. Digital distribution means the product itself is delivered digitally (e.g. a downloaded game or e-book) with no physical delivery required.</p>", "question": "What is the key difference between e-commerce and digital distribution?", "options": ["Digital distribution always involves a physical shop instead", "E-commerce involves physical delivery, unlike digital", "They mean exactly the same thing in every situation", "E-commerce never involves any kind of delivery at all"]}'::jsonb, '{"answer": 1, "explain": "E-commerce involves an online sale followed by physical delivery, while digital distribution delivers the product itself digitally, e.g. a downloaded game or e-book."}'::jsonb),
('business:4-3-sales-process-customer-service:misc:e5cdaa6c', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Telesales is becoming irrelevant because of e-commerce.</p><p><strong>✅ The correct idea:</strong> Telesales remains important as a bridge between e-commerce and face-to-face selling, particularly for older customers, subscription renewals (insurance, utilities, phone contracts), and situations where customers want to negotiate directly.</p>", "question": "Is telesales becoming irrelevant because of e-commerce?", "options": ["Yes – no businesses run telesales departments anymore at all", "No – it remains important as a bridge for older customers", "Yes – it has been entirely replaced by e-commerce websites", "No – it is now more popular than face-to-face selling"]}'::jsonb, '{"answer": 1, "explain": "Telesales remains important, particularly for older customers, subscription renewals, and customers who want to negotiate directly."}'::jsonb),
('business:4-3-sales-process-customer-service:tips:b9e3dce1', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation. No case study. No paragraphs.</p>\n      <p><strong>The Formula:</strong> One specific, correct point = 1 mark ✅</p>\n      <ul>\n        <li><strong>❌ Bad Answer (0 marks):</strong> <em>\"Promotion.\"</em> — This is a marketing concept, not a method of selling.</li>\n        <li><strong>✅ Good Answer (1 mark):</strong> <em>\"E-commerce / telesales / face to face selling.\"</em></li>\n      </ul>\n      <p><strong>⚠️ Examiner Warning:</strong> Many students lost marks by writing promotional methods (price skimming, advertising) when asked for a <em>method of selling</em>. Read the exact question wording before writing.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a definition when asked to ''identify''. Just name the thing.</p>\n    ", "question": "For a 1-mark ''State'' or ''Identify'' question, what should your answer contain?", "options": ["A full paragraph with U, APP and AN chains", "One specific point, no explanation needed", "Two safety points, one per mark", "A dictionary-style term definition"]}'::jsonb, '{"answer": 1, "explain": "The tip states a 1-mark identify/state question needs exactly one correct point — no explanation, no case study."}'::jsonb),
('business:4-3-sales-process-customer-service:tips:e10de8f1', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Point + Explain = 2 Marks", "reading": "\n      <p>For a 2-mark <strong>''Explain''</strong> question, you need a point AND an explanation of how it works. Two sentences — two marks.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Sentence 1 — State the point (K/U):</strong> Name the advantage, disadvantage, or concept.</li>\n        <li><strong>Sentence 2 — Explain it (U):</strong> Say WHY or HOW it works.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/><em>\"E-commerce means the business can sell more.\"</em><br/>Too vague — doesn''t explain the mechanism.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/><em>\"A business using e-commerce has lower operating costs (1) because it does not need to pay expensive city-centre rents for a physical shop (1).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Some students answered from the customer''s perspective when asked about a business advantage. Re-read: who does the question say the advantage is FOR?</p>\n    ", "question": "What error did the guide flag as a common mistake on this 2-mark ''explain'' question about a business advantage?", "options": ["Answering from the customer''s view, not the firm''s", "Forgetting to name the business anywhere at all", "Using bullet points, not full written sentences", "Writing far too much content for the marks given"]}'::jsonb, '{"answer": 0, "explain": "The examiner warning notes some students answered from the customer''s perspective when the question asked about a business advantage."}'::jsonb),
('business:4-3-sales-process-customer-service:tips:589551e5', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark analyse question requires all three elements. You will score <strong>ZERO for analysis</strong> if you don''t apply your answer to the specific business in the case study.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the theory or benefit clearly.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Directly reference the case study business with specific text evidence.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the financial or operational IMPACT on the business.</li>\n      </ul>\n      <p><strong>Sentence Starters:</strong></p>\n      <ul>\n        <li><em>U: \"Good product knowledge means staff can advise customers on...\"</em></li>\n        <li><em>APP: \"In the case of [Business Name], the text states that...\"</em></li>\n        <li><em>AN: \"This will lead to more sales, meaning...\" / \"As a result, the business will...\"</em></li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Product knowledge helps employees advise customers so they buy more.\"</em><br/>No application to the specific business = maximum 1 mark.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"Call centre employees need to be able to advise customers on what is best to buy (U). AZ''s products are sold to qualified medical professionals, hospitals and governments (APP), so if employees cannot answer technical questions, sales and profits may fall (AN).\"</em></p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do not write everything you know about the topic. Answer the specific question with reference to the specific business.</p>\n    ", "question": "In the U → APP → AN structure for a 3-mark analyse question, what does ''APP'' require?", "options": ["A general definition of the relevant business theory", "A concluding evaluation using the ''it depends'' rule", "A clear judgement or final recommendation on the issue", "Direct reference to the case study business with evidence"]}'::jsonb, '{"answer": 3, "explain": "Application (APP) means directly referencing the case study business with specific text evidence — without it, you score zero for analysis."}'::jsonb),
('business:4-3-sales-process-customer-service:tips:b3a214a0', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (Two impacts) — 6 marks — Two 3-Mark Chains. No Conclusion Needed.", "reading": "\n      <p>A 6-mark question is simply a <strong>3-mark question done twice</strong>. You must analyse TWO separate impacts, each with its own U → APP → AN chain.</p>\n      <p><strong>⚠️ Critical Warning:</strong> There are <strong>ZERO marks</strong> available for a conclusion or evaluation here. Do NOT write \"Overall, I think...\" — it wastes time and scores nothing.</p>\n      <p><strong>Structure:</strong></p>\n      <ul>\n        <li><strong>Impact 1 (3 marks):</strong> U → APP → AN</li>\n        <li><strong>Impact 2 (3 marks):</strong> U → APP → AN</li>\n      </ul>\n      <p><strong>Sentence Starters for each paragraph:</strong></p>\n      <ul>\n        <li><em>\"One advantage/disadvantage is that... (U)\"</em></li>\n        <li><em>\"In the case of [Business], the text tells us that... (APP)\"</em></li>\n        <li><em>\"This means that... resulting in... (AN)\"</em></li>\n      </ul>\n      <p><strong>⚠️ Examiner Warning (Primark question):</strong> Many students wrote from the CUSTOMER''S point of view when the question asked about Primark Ltd. If the question says \"to Primark Ltd,\" every point must show how PRIMARK is affected — not how customers feel about it.</p>\n    ", "question": "How many marks are available for a conclusion or evaluation in a 6-mark ''analyse two impacts'' question?", "options": ["Six", "Zero", "One", "Three"]}'::jsonb, '{"answer": 1, "explain": "The guide is explicit that there are zero marks for a conclusion in a 6-mark ''two impacts'' analyse question — writing ''Overall, I think...'' wastes time and scores nothing."}'::jsonb),
('business:4-3-sales-process-customer-service:tips:4ce429a4', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Decision + Contextual Justification", "reading": "\n      <p>A 3-mark recommend question is NOT just a repeat of advantages and disadvantages. It needs a <strong>clear decision</strong> supported by a <strong>contextual justification</strong>.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>1 mark — Judgement:</strong> Make a clear recommendation (should / should not).</li>\n        <li><strong>2 marks — Contextual justification:</strong> Use EVIDENCE from the case study text to support your decision. The evidence must be USED (not just repeated).</li>\n        <li><strong>OR 1 mark — Non-contextual justification:</strong> A reason without specific text reference.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Primark should continue click and collect because it is good for customers.\"</em><br/>Wrong perspective, no context used.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"Primark should continue (JUDGEMENT). If it stops, it may lose customers who have already changed their buying habits and got used to ordering online, as the text states buying habits have already changed (CONTEXT). This would reduce Primark''s revenue and market share. (+2 MARKS)\"</em></p>\n      <p><strong>⚠️ Examiner Comment:</strong> Less than a quarter of students got full marks on this type of question. Most could make a recommendation but could not justify it using the context — they repeated the text rather than using it to support their argument.</p>\n    ", "question": "What does a full 3-mark ''recommend'' answer require beyond a simple advantage/disadvantage list?", "options": ["An evaluation paragraph using the ''it depends'' rule", "A clear judgement supported by contextual justification", "A list of three separate recommendations for the business", "Only a simple yes or no decision with no reasoning"]}'::jsonb, '{"answer": 1, "explain": "A 3-mark recommend answer needs 1 mark for judgement and 2 marks for contextual justification, using case study evidence that is actually used, not just repeated."}'::jsonb),
('business:4-3-sales-process-customer-service:tips:2f84d3dd', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — Four-Paragraph Structure for Full Marks", "reading": "\n      <p>A 9-mark evaluate question tests your ability to argue both sides and make a justified judgement. Structure your answer in <strong>four paragraphs</strong>:</p>\n      <ul>\n        <li><strong>Paragraph 1 — Knowledge & Understanding (K + U):</strong> Define key concepts relevant to the question (e.g. what customer service is, what growth means as a business objective).</li>\n        <li><strong>Paragraph 2 — First side with analysis (AN + APP):</strong> Argue FOR the importance of customer service, with a full chain of reasoning linked to the specific business.</li>\n        <li><strong>Paragraph 3 — Counterargument with analysis (AN + APP):</strong> Argue against or present a counter-view (e.g. other factors affecting growth such as price or competition from no-frills rivals).</li>\n        <li><strong>Paragraph 4 — Evaluation (EVAL — 3 marks):</strong> Write a justified conclusion using the \"It depends on...\" rule. Decision + Context + Impact/Reasoning.</li>\n      </ul>\n      <p><strong>Evaluation Sentence Starters:</strong></p>\n      <ul>\n        <li><em>\"Overall, good customer service is important to Virgin Atlantic achieving growth because...\"</em></li>\n        <li><em>\"However, this depends on whether Virgin Atlantic is targeting price-conscious customers or premium travellers...\"</em></li>\n        <li><em>\"In conclusion, I recommend... because... but this depends on...\"</em></li>\n      </ul>\n      <p><strong>⚠️ Evaluation Warning:</strong> A conclusion that only repeats what you already wrote scores ZERO for evaluation. The \"It depends on...\" must introduce a NEW condition or consideration not already covered.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT list every fact you know about customer service. Every sentence must be specifically linked to the business''s objective in the question.</p>\n    ", "question": "According to the guide, what makes a concluding ''it depends on...'' statement score zero for evaluation?", "options": ["Failing to mention the business by name", "Repeating earlier points instead of a new condition", "Placing it in paragraph four, not paragraph one", "Writing fewer than two full sentences"]}'::jsonb, '{"answer": 1, "explain": "The evaluation warning states a conclusion that only repeats what was already written scores zero — the ''it depends'' must introduce a new condition not already covered."}'::jsonb),
('business:4-3-sales-process-customer-service:tips:8d63ab7f', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Perspective Trap — All Questions — Business vs Customer: Never Mix These Up", "reading": "\n      <p>One of the most common ways students lose marks in 4.3 is answering from the <strong>wrong perspective</strong>.</p>\n      <p><strong>Always identify WHO the question is asking about before you write:</strong></p>\n      <ul>\n        <li>If the question says \"advantage to the BUSINESS\" — every point must show how the BUSINESS benefits.</li>\n        <li>If the question says \"disadvantage to the CUSTOMER\" — every point must show how the CUSTOMER is negatively affected.</li>\n      </ul>\n      <p><strong>Examples of the perspective trap:</strong></p>\n      <ul>\n        <li><strong>❌ Wrong (0 marks):</strong> Answering \"customers can''t touch the product\" when asked about a disadvantage to M&S of selling food via e-commerce. That is a customer disadvantage.</li>\n        <li><strong>✅ Right (1 mark):</strong> \"M&S may suffer reputational damage if its website crashes, leading to a loss of customers and reduced revenue.\" — This is a business disadvantage.</li>\n      </ul>\n      <p><strong>⚠️ Direct Examiner Quote:</strong> On the Primark question, many students wrote advantages and disadvantages from the customer''s point of view even when the question clearly asked about Primark Ltd. This was one of the main reasons students scored 0 marks on that question.</p>\n    ", "question": "On the Primark question referenced in the guide, what was the main reason many students scored 0 marks?", "options": ["They wrote points from the customer''s view, not Primark''s", "They ran out of exam time before finishing the answer", "They used bullet points instead of full written paragraphs", "They forgot to mention click and collect at all"]}'::jsonb, '{"answer": 0, "explain": "The direct examiner quote notes many students wrote from the customer''s point of view even though the question asked about Primark Ltd, causing them to score 0."}'::jsonb),
