('business:4-3-sales-process-customer-service:match:dfb92d35', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “E-commerce”?", "options": ["Usually completed in a shop where there is direct contact between buyer and seller.", "An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal.", "The bringing together of buying and selling electronically.", "Ordering online and collecting goods from store at a later time."]}'::jsonb, '{"answer": 2, "explain": "“E-commerce” means: The bringing together of buying and selling electronically."}'::jsonb),
('business:4-3-sales-process-customer-service:match:29bc740e', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer service”?", "options": ["Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance.", "An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal.", "The name given to an area of business that deals with customer enquiries.", "Advice and help given to a customer after they have bought a product or service."]}'::jsonb, '{"answer": 2, "explain": "“Customer service” means: The name given to an area of business that deals with customer enquiries."}'::jsonb),
('business:4-3-sales-process-customer-service:match:824623fd', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer engagement”?", "options": ["Advice and help given to a customer after they have bought a product or service.", "The bringing together of buying and selling electronically.", "The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce.", "The contact between the business and customer."]}'::jsonb, '{"answer": 3, "explain": "“Customer engagement” means: The contact between the business and customer."}'::jsonb),
('business:4-3-sales-process-customer-service:match:1e57b9f6', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Click and collect”?", "options": ["The bringing together of buying and selling electronically.", "Advice and help given to a customer after they have bought a product or service.", "Ordering online and collecting goods from store at a later time.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy."]}'::jsonb, '{"answer": 2, "explain": "“Click and collect” means: Ordering online and collecting goods from store at a later time."}'::jsonb),
('business:4-3-sales-process-customer-service:match:f61a3c15', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Face to face selling”?", "options": ["Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance.", "Sales completed over the telephone.", "The contact between the business and customer.", "Usually completed in a shop where there is direct contact between buyer and seller."]}'::jsonb, '{"answer": 3, "explain": "“Face to face selling” means: Usually completed in a shop where there is direct contact between buyer and seller."}'::jsonb),
('business:4-3-sales-process-customer-service:match:8ec5977f', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Telesales”?", "options": ["Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance.", "Sales completed over the telephone.", "Usually completed in a shop where there is direct contact between buyer and seller.", "Ordering online and collecting goods from store at a later time."]}'::jsonb, '{"answer": 1, "explain": "“Telesales” means: Sales completed over the telephone."}'::jsonb),
('business:4-3-sales-process-customer-service:match:c1a931d3', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “After-sales service”?", "options": ["The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.", "Advice and help given to a customer after they have bought a product or service.", "A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors."]}'::jsonb, '{"answer": 2, "explain": "“After-sales service” means: Advice and help given to a customer after they have bought a product or service."}'::jsonb),
('business:4-3-sales-process-customer-service:match:0ce1744b', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Product knowledge”?", "options": ["Usually completed in a shop where there is direct contact between buyer and seller.", "The bringing together of buying and selling electronically.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.", "An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal."]}'::jsonb, '{"answer": 2, "explain": "“Product knowledge” means: The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy."}'::jsonb),
('business:4-3-sales-process-customer-service:match:09c9f47d', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price comparison”?", "options": ["Advice and help given to a customer after they have bought a product or service.", "The bringing together of buying and selling electronically.", "An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal.", "The name given to an area of business that deals with customer enquiries."]}'::jsonb, '{"answer": 2, "explain": "“Price comparison” means: An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal."}'::jsonb),
('business:4-3-sales-process-customer-service:match:b46aef5c', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cold calling”?", "options": ["The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce.", "The contact between the business and customer.", "Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance.", "Sales completed over the telephone."]}'::jsonb, '{"answer": 2, "explain": "“Cold calling” means: Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance."}'::jsonb),
('business:4-3-sales-process-customer-service:match:bbe41fe0', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Logistics”?", "options": ["Sales completed over the telephone.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.", "The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce.", "Advice and help given to a customer after they have bought a product or service."]}'::jsonb, '{"answer": 2, "explain": "“Logistics” means: The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce."}'::jsonb),
('business:4-3-sales-process-customer-service:match:9787c244', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Amazon Prime”?", "options": ["A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.", "The bringing together of buying and selling electronically.", "The contact between the business and customer."]}'::jsonb, '{"answer": 0, "explain": "“Amazon Prime” means: A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors."}'::jsonb),
('business:4-4-consumer-law:exam:cb64d624', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q2", "question": "A company makes wooden jigsaw puzzles. By law, the company must: [1 mark]", "options": ["Buy its wood from local suppliers", "Deliver the jigsaw puzzles in electric vans", "Replace any pieces that customers lose", "Use paint that is non-toxic and safe"], "hint": "Consumer law is about the safety and quality of the product itself — not about where raw materials come from or how the product is delivered.", "starter": "The correct answer is D, because consumer law requires goods to be..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Use paint that is non-toxic and safe (1 mark)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Buy its wood from local suppliers:</strong> Consumer law does not specify where raw materials must be sourced from. Using local suppliers may be an ethical or logistical choice, but it has no legal requirement under the Consumer Rights Act 2015.</li><li><strong>B — Deliver in electric vans:</strong> The method of delivery is not regulated by consumer law. This may relate to environmental responsibility, but the Consumer Rights Act does not require a specific delivery method.</li><li><strong>C — Replace pieces customers lose:</strong> The Consumer Rights Act does not require businesses to replace items lost through customer negligence. Consumer rights apply to faults present at the time of purchase — not losses caused by the customer.</li><li><strong>D — Use non-toxic and safe paint (CORRECT):</strong> Consumer law requires goods to be of satisfactory quality and safe to use. Using non-toxic paint ensures the product is safe for the consumer — especially critical for a product that children might handle.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-4-consumer-law:exam:4e560506', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q3", "question": "A customer has bought a laptop from a computer shop. By law, the computer shop must: [1 mark]", "options": ["Match the price charged by a local competitor", "Offer to upgrade the laptop for no extra charge", "Provide virus protection to keep the customer''s files safe", "Supply a laptop of satisfactory quality"], "hint": "Think about the three key requirements of the Consumer Rights Act 2015. Which one applies directly here?", "starter": "The correct answer is D, because the Consumer Rights Act requires goods to be..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Supply a laptop of satisfactory quality (1 mark — AO2)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Match the price of a local competitor:</strong> Price matching is not a legal requirement. Consumer law does not regulate pricing — businesses are free to charge what they choose.</li><li><strong>B — Offer a free upgrade:</strong> Upgrades are a customer service gesture, not a legal obligation. The Consumer Rights Act does not require businesses to offer product upgrades at any point.</li><li><strong>C — Provide virus protection:</strong> Installing software or providing cybersecurity is not a requirement under consumer law. It may be offered as an extra service, but the Consumer Rights Act 2015 does not mandate it.</li><li><strong>D — Supply a laptop of satisfactory quality (CORRECT):</strong> The Consumer Rights Act 2015 requires all goods to be of satisfactory quality — free from defects and appropriate for the price paid. This is the core legal obligation of any seller.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-4-consumer-law:exam:5ce53b29', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q5", "question": "A customer has ordered an electric shower from a plumbing firm. By law, the plumbing firm must: [1 mark]", "options": ["Charge a lower price than other plumbers", "Fit the shower without turning the water off", "Supply a shower that meets current safety standards", "Use an environmentally friendly supplier"], "hint": "Consumer law focuses on the safety and quality of goods supplied — not on pricing or the environmental sourcing of materials.", "starter": "The correct answer is C, because consumer law requires goods to be..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Supply a shower that meets current safety standards (1 mark)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Charge a lower price than other plumbers:</strong> Pricing is not regulated by consumer law. There is no legal obligation to undercut competitors — businesses are free to set their own prices.</li><li><strong>B — Fit the shower without turning the water off:</strong> This is not a requirement of consumer law, and would in fact be dangerous and unsafe — directly contradicting the spirit of consumer protection legislation.</li><li><strong>C — Supply a shower that meets current safety standards (CORRECT):</strong> Consumer law requires goods and services to be of satisfactory quality, which includes meeting current safety standards. A shower must be safe, functional, and fit for the purpose of providing hot water.</li><li><strong>D — Use an environmentally friendly supplier:</strong> Environmental sourcing is an ethical consideration, not a legal consumer law requirement. Consumer law is about the rights of the buyer — not the environmental practices of the supply chain.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-4-consumer-law:exam:e0ef9818', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Consumer law requires shops to sell goods that are: [1 mark]", "options": ["Cheap", "High quality", "Safe", "Unique"], "hint": "Consumer law doesn''t require goods to be the best or the cheapest — think about the word used in the law itself for the quality requirement.", "starter": "The correct answer is C, because consumer law requires goods to be..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Safe (1 mark — AO1a)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Cheap:</strong> Consumer law does not require goods to be cheap. There is no price regulation in the Consumer Rights Act 2015 — businesses are free to charge market rates.</li><li><strong>B — High quality:</strong> This is the most common wrong answer. The law requires ''satisfactory quality'' — a standard that reflects the price paid — NOT the highest possible quality. Luxury goods must be high quality; budget goods only need to meet a lower, price-appropriate standard.</li><li><strong>C — Safe (CORRECT):</strong> Consumer law requires goods to be safe and of satisfactory quality. Safety is a core requirement — goods must not cause harm to the consumer when used as intended.</li><li><strong>D — Unique:</strong> Consumer law places no requirement on uniqueness or exclusivity. There is no legal reason a business cannot sell standard, mass-produced goods.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-4-consumer-law:exam:1422879a', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Consumer law requires shops to sell goods which are: [1 mark]", "options": ["Environmentally friendly", "Of satisfactory quality", "Reasonably priced", "Unique"], "hint": "Think about the exact wording used in the Consumer Rights Act 2015 for the quality requirement.", "starter": "The correct answer is B, because the Consumer Rights Act 2015 specifically states that goods must be..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Of satisfactory quality (1 mark — AO1a)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Environmentally friendly:</strong> Environmental responsibility is an ethical choice, not a legal consumer law requirement. The Consumer Rights Act 2015 makes no mention of environmental standards.</li><li><strong>B — Of satisfactory quality (CORRECT):</strong> The Consumer Rights Act 2015 specifically requires goods to be of satisfactory quality — not defective or damaged when sold, and appropriate for the price paid. This is one of the three core legal requirements.</li><li><strong>C — Reasonably priced:</strong> Consumer law does not regulate pricing. Businesses are free to charge market rates. ''Reasonably priced'' is not a requirement found anywhere in the Consumer Rights Act 2015.</li><li><strong>D — Unique:</strong> Consumer law places no requirement on uniqueness. Mass-produced, standard goods are perfectly legal to sell and fully covered by consumer law.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-4-consumer-law:mcq:08014156', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "When buying any goods or services, customers are entitled to expect:", "options": ["The goods to be of the best standard possible", "The goods to be of satisfactory quality", "The goods to be guaranteed for three years", "The goods to be the same price as competitors"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Of satisfactory quality. The Consumer Rights Act 2015 requires goods to be of ''satisfactory quality'' reflecting their price — not the absolute best quality possible. There is no legal requirement for a guarantee period, price matching, or best-in-class standards."}'::jsonb),
('business:4-4-consumer-law:mcq:0a905c12', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A business must sell goods that:", "options": ["Do what they are meant to do", "Perform as well as competitor goods", "Are made to last for years", "Are as cheap as possible"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: Do what they are meant to do. This is the ''fit for purpose'' requirement of the Consumer Rights Act 2015. Businesses have no legal obligation to match competitors'' performance, guarantee longevity, or price goods cheaply."}'::jsonb),
('business:4-4-consumer-law:mcq:f2078ada', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A way in which a business can be affected by consumer law is:", "options": ["Having compensation claims because goods are of high quality", "Losing reputation due to defective goods", "Having to sack staff who are always late for work", "Profits being reduced by paying higher wages"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Losing reputation due to defective goods. Producing defective goods leads to customer complaints, negative social media posts, and a damaged reputation. Sacking staff and wage levels are employment law issues — not consumer law."}'::jsonb),
('business:4-4-consumer-law:mcq:80a9cb40', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "The loss of a good reputation may mean a business:", "options": ["Can spend less money on advertising its products", "Has to increase production to meet demand", "Can afford to give staff a pay rise", "May have difficulty in recruiting staff"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: May have difficulty recruiting staff. A poor reputation makes it harder to attract talented workers who want to be associated with respected companies. A damaged reputation would not reduce advertising needs, increase demand, or free up funds for pay rises."}'::jsonb),
('business:4-4-consumer-law:mcq:8e110c30', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A company makes wooden jigsaw puzzles. By law, the company must:", "options": ["Buy its wood from local suppliers", "Deliver the jigsaw puzzles in electric vans", "Replace any pieces that customers lose", "Use paint that is non-toxic and safe"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: Use paint that is non-toxic and safe. Consumer law requires goods to be safe and of satisfactory quality. Using non-toxic paint ensures the product is safe to handle. There is no legal requirement to use local suppliers, deliver by electric van, or replace pieces lost through customer negligence."}'::jsonb),
('business:4-4-consumer-law:mcq:4eaf64d2', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A customer has bought a laptop from a computer shop. By law, the computer shop must:", "options": ["Match the price charged by a local competitor", "Offer to upgrade the laptop for no extra charge", "Provide virus protection to keep the customer''s files safe", "Supply a laptop of satisfactory quality"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: Supply a laptop of satisfactory quality. The Consumer Rights Act 2015 requires goods to be of satisfactory quality — free from defects. Price matching, upgrades, and virus protection may be offered as good customer service, but none are required by law."}'::jsonb),
('business:4-4-consumer-law:mcq:ecbacf95', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A customer has ordered an electric shower from a plumbing firm. By law, the plumbing firm must:", "options": ["Charge a lower price than other plumbers", "Fit the shower without turning the water off", "Supply a shower that meets current safety standards", "Use an environmentally friendly supplier"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Supply a shower that meets current safety standards. Consumer law requires goods and services to be safe and of satisfactory quality. There is no legal requirement to undercut competitors'' prices, use a specific installation method, or source from eco-friendly suppliers."}'::jsonb),
('business:4-4-consumer-law:mcq:8b7f2ba4', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Consumer law requires shops to sell goods that are:", "options": ["Cheap", "High quality", "Safe", "Unique"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Safe. Consumer law requires goods to be safe (of satisfactory quality and fit for purpose). ''High quality'' is a very common distractor — the law only requires ''satisfactory'' quality, not the highest quality. Price and uniqueness are not legal requirements."}'::jsonb),
('business:4-4-consumer-law:mcq:f04710e6', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Consumer law requires shops to sell goods which are:", "options": ["Environmentally friendly", "Of satisfactory quality", "Reasonably priced", "Unique"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Of satisfactory quality. The Consumer Rights Act 2015 specifically requires goods to be of satisfactory quality — not defective or damaged when sold. Environmental responsibility, pricing, and uniqueness are not legal requirements under consumer law."}'::jsonb),
('business:4-4-consumer-law:mcq:dfdbce5c', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Within how many days can a customer return faulty goods for a full refund under the Consumer Rights Act 2015?", "options": ["14 days", "21 days", "30 days", "60 days"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: 30 days. The Consumer Rights Act 2015 gives customers a 30-day window to return faulty goods for a full refund. After 30 days, the right to an automatic full refund ends — within 6 months, a repair or replacement is offered first."}'::jsonb),
('business:4-4-consumer-law:mcq:c993e623', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "If a product develops a fault within the first six months of purchase, who must prove the fault was pre-existing?", "options": ["The customer", "The manufacturer", "The seller", "An independent tribunal"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: The seller. Within the first 6 months, it is assumed the fault was present at the time of purchase. The seller must prove otherwise. After 6 months, the burden of proof shifts to the customer."}'::jsonb),
('business:4-4-consumer-law:mcq:2c56f9d0', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a requirement of the Consumer Rights Act 2015?", "options": ["Of satisfactory quality", "Fit for purpose", "As described", "Cheapest price on the market"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: Cheapest price on the market. The three requirements under the Consumer Rights Act 2015 are: satisfactory quality, fit for purpose, and as described. There is no requirement for businesses to sell at the lowest market price."}'::jsonb),
('business:4-4-consumer-law:tf:f24e6c65', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "The Consumer Rights Act says that goods must always be of the best possible quality."}'::jsonb, '{"answer": false, "explain": "FALSE. The Consumer Rights Act only requires goods to be of ''satisfactory quality'' — a standard that reflects the price paid. Cheaper goods have a lower quality expectation than luxury goods; they do not all need to be the best possible standard."}'::jsonb),
('business:4-4-consumer-law:tf:da697871', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Customers can return faulty goods for a full refund within 30 days of purchase."}'::jsonb, '{"answer": true, "explain": "TRUE. The Consumer Rights Act 2015 gives customers a 30-day window to return faulty goods for a full refund. Businesses must comply with this legal right."}'::jsonb),
('business:4-4-consumer-law:tf:ef115baa', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "All goods must be described correctly only when they are over £100."}'::jsonb, '{"answer": false, "explain": "FALSE. The ''as described'' requirement applies to ALL goods regardless of their price. Whether a product costs £1 or £1,000, it must match its description exactly."}'::jsonb),
('business:4-4-consumer-law:tf:49f18b9f', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Safety in goods bought by customers is covered by the Consumer Protection Act 1987."}'::jsonb, '{"answer": true, "explain": "TRUE. The Consumer Protection Act 1987 gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury — specifically covering product safety."}'::jsonb),
('business:4-4-consumer-law:tf:44b66e9d', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Digital goods such as downloaded music are covered in exactly the same way as physical goods by the Consumer Rights Act."}'::jsonb, '{"answer": false, "explain": "FALSE. Digital products such as downloaded music and apps are NOT covered by the 30-day return rule. Instead, customers can request a replacement or, if not provided, a price reduction of up to 100%."}'::jsonb),
('business:4-4-consumer-law:tf:9e9bf9f6', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Good training of employees will help a business produce goods of satisfactory quality."}'::jsonb, '{"answer": true, "explain": "TRUE. Investing in employee training helps businesses produce goods that meet the satisfactory quality standard required by consumer law. This directly links to Unit 3.6 (Training)."}'::jsonb),
('business:4-4-consumer-law:tf:368ca0fb', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "After 30 days, a customer cannot make any claim whatsoever for faulty goods against a business."}'::jsonb, '{"answer": false, "explain": "FALSE. After 30 days, the right to a full refund ends, but customers retain rights. Within 6 months, they can request a repair or replacement. After 6 months, they can still claim for up to six years if they prove the fault was present at the time of purchase."}'::jsonb),
('business:4-4-consumer-law:tf:8a94e33a', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "A business can face compensation claims if its products cause personal injury or death."}'::jsonb, '{"answer": true, "explain": "TRUE. Under the Consumer Protection Act 1987, customers can claim compensation for death, damage, or personal injury caused by defective products. This can result in huge financial costs for the business."}'::jsonb),
('business:4-4-consumer-law:tf:a3975e62', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Consumer law only applies to physical products and does not cover services such as plumbing or hairdressing."}'::jsonb, '{"answer": false, "explain": "FALSE. The Consumer Rights Act 2015 also covers services. If a service is not completed in the agreed time or to a reasonable standard, customers can request the work to be redone or receive a price reduction of up to 100%."}'::jsonb),
('business:4-4-consumer-law:tf:9aae27fc', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "If a fault develops after six months, it is the seller''s responsibility to prove the fault was not there at the time of purchase."}'::jsonb, '{"answer": false, "explain": "FALSE. After six months, the burden of proof shifts to the customer — they must prove the fault existed at the time of delivery. Within the first six months, it is the seller who must prove otherwise."}'::jsonb),
('business:4-4-consumer-law:tf:12b98971', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "A business that complies with consumer law may benefit from an improved reputation."}'::jsonb, '{"answer": true, "explain": "TRUE. Consistently selling goods that are of satisfactory quality, fit for purpose, and as described helps build a strong reputation, increasing customer loyalty and sales over time."}'::jsonb),
('business:4-4-consumer-law:tf:afb84288', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Social media makes it easier for businesses to conceal poor quality products from consumers."}'::jsonb, '{"answer": false, "explain": "FALSE. Social media makes it significantly harder for businesses to conceal product issues. Customers can post negative reviews publicly and these can spread rapidly, causing serious reputational damage far beyond the original complaint."}'::jsonb),
('business:4-4-consumer-law:learn:f912d89b', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Consumer law protects customers when they buy goods and services. The main piece of legislation you need to understand is the <strong>Consumer Rights Act 2015</strong>.</p>\n    <ul>\n      <li><strong>Consumer Law:</strong> The area of law that protects the customers of a business. This is mainly through the Consumer Rights Act 2015.</li>\n      <li><strong>Consumer Rights Act 2015:</strong> An act of parliament that gives customers protection when they buy goods and services — they must be of satisfactory quality, fit for purpose, and as described.</li>\n      <li><strong>Satisfactory Quality:</strong> How the goods are made must reflect the price. A high-priced product must be of high quality. Goods must not be damaged or faulty when bought.</li>\n      <li><strong>Fit for Purpose:</strong> Goods must do what they are meant to do. If the seller claims that a product performs a particular function, it must be able to do that.</li>\n      <li><strong>As Described:</strong> Goods must be exactly as described or advertised. If you ordered an orange-coloured bike, you should receive an orange bike — not a green one.</li>\n      <li><strong>Reputation:</strong> What customers say and feel about a business. Damage to a reputation can seriously affect a business''s long-term survival and sales.</li>\n      <li><strong>Compensation:</strong> A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987.</li>\n      <li><strong>Consumer Protection Act 1987:</strong> Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.</li>\n    </ul>", "question": "Under which act can consumers claim compensation if a defective product causes death, damage, or personal injury?", "options": ["Consumer Protection Act 1987", "Trade Descriptions Act 1968", "Consumer Rights Act 2015", "Sale of Goods Act 1979"]}'::jsonb, '{"answer": 0, "explain": "The Consumer Protection Act 1987 specifically gives consumers the right to claim compensation for defective products causing death, damage, or personal injury."}'::jsonb),
('business:4-4-consumer-law:learn:3acd86e6', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "The Consumer Rights Act 2015: The Three Requirements", "reading": "<p>The <strong>Consumer Rights Act 2015</strong> is the key law protecting customers in the UK. It states that all goods and services sold to customers must meet three requirements. Businesses that fail to comply face serious legal and financial consequences.</p>\n    <ul>\n      <li><strong>1. Of Satisfactory Quality:</strong> Goods must not be damaged or faulty when bought. The quality expected should reflect the price paid — cheaper ''bargains'' are expected to have lower quality than luxury goods. All goods must be appropriate for their price point.</li>\n      <li><strong>2. Fit for Purpose:</strong> Goods must do what they are meant to do. If the seller claims a product performs a specific function, it must be able to do it. For example, a waterproof jacket must actually be waterproof.</li>\n      <li><strong>3. As Described:</strong> Goods must match their description exactly. If you order orange trainers online, you should receive orange ones — not blue ones.</li>\n    </ul>\n    <div class=\"case-study-box\">\n      <h4>Applying the Three Requirements — Real Scenarios</h4>\n      <p><strong>Lisa</strong> buys a washing machine and the start button doesn''t work &rarr; <em>Not of satisfactory quality</em> (faulty when bought).</p>\n      <p><strong>Mandy</strong> buys face cream claiming to eliminate wrinkles, but it doesn''t work &rarr; <em>Not fit for purpose</em> (does not do what it claims).</p>\n      <p><strong>Tim</strong> orders a blue top online but receives a green one &rarr; <em>Not as described</em> (product does not match its description).</p>\n      <p><strong>Oliver</strong> buys a jumper in the sale and finds the seam is ripped when he gets home &rarr; Could be <em>not of satisfactory quality</em> — even sale goods must meet basic standards unless the fault was pointed out at the time of purchase.</p>\n    </div>", "question": "Mandy buys face cream claiming to eliminate wrinkles, but it doesn''t work. Which requirement has been breached?", "options": ["Satisfactory quality", "Fit for purpose", "Consumer Protection Act 1987", "As described"]}'::jsonb, '{"answer": 1, "explain": "The cream fails to do what the seller claimed it would do, so it is not fit for purpose."}'::jsonb),
('business:4-4-consumer-law:learn:8b727b30', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Time-Based Customer Rights Under the Consumer Rights Act", "reading": "<p>The Consumer Rights Act also gives customers specific rights depending on <strong>when</strong> a fault is discovered after purchase. These rights change at key time thresholds.</p>\n    <ul>\n      <li><strong>Within 30 Days — Full Refund:</strong> A customer can return faulty goods for a full refund. Important exception: this does <strong>NOT</strong> apply to digital products such as downloaded music or apps. For digital goods, a customer can request a replacement or, if not provided, a price reduction of up to 100%.</li>\n      <li><strong>Within the First 6 Months — Seller''s Burden of Proof:</strong> If a product develops a fault within the first six months, it is assumed the fault was present at the time of purchase. The <strong>seller</strong> must prove otherwise. The customer may request a repair, replacement, or price reduction.</li>\n      <li><strong>After 6 Months — Customer''s Burden of Proof:</strong> It is up to the <strong>customer</strong> to prove that the fault was present at the time of delivery. This is significantly more difficult. Customers have up to <strong>six years</strong> to complete a claim against the seller.</li>\n      <li><strong>Services:</strong> If a service (e.g. a kitchen fitter or plumber) is not completed in the agreed time or to a reasonable standard, the customer can request the work to be redone. If that is not possible, a price reduction of up to 100% should be agreed.</li>\n    </ul>", "question": "Within how many months of purchase does the burden of proof fall on the seller, not the customer, to show a fault wasn''t present at purchase?", "options": ["12 months", "30 days", "6 months", "6 years"]}'::jsonb, '{"answer": 2, "explain": "Within the first 6 months, a fault is assumed to have been present at purchase and the seller must prove otherwise."}'::jsonb),
('business:4-4-consumer-law:learn:e5ee9b3f', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "The Impact of Consumer Law on Business", "reading": "<p>Consumer law has several significant impacts on how a business must operate. Businesses need to plan carefully to comply — and face serious consequences if they do not.</p>\n    <ul>\n      <li><strong>Production of Quality Goods:</strong> Businesses must ensure goods are produced to a standard that meets legal requirements. This affects how businesses train employees (links to Unit 3.6) and what quality control procedures they use (links to Unit 4.2). If goods are returned for refunds, costs increase and profits fall.</li>\n      <li><strong>Safety of Goods:</strong> Under the Consumer Protection Act 1987, if defective products cause death, injury, or damage to property, customers can claim compensation. This can result in huge financial costs and forces firms to maintain strict safety procedures throughout production.</li>\n      <li><strong>Loss of Reputation:</strong> If a business produces poor-quality or defective goods, customers will complain — often publicly on social media. Negative reviews spread rapidly, damaging a business''s reputation and driving customers to competitors. In extreme cases, this could lead to the business closing down entirely.</li>\n      <li><strong>Training Costs:</strong> To comply with consumer law, businesses must invest in training employees to produce goods of the required quality standard. This increases operating costs but reduces the risk of producing defective goods that lead to costly refunds or legal claims.</li>\n    </ul>", "question": "According to this topic, what is the main risk when customers complain about poor-quality goods online?", "options": ["Customers permanently lose their refund rights", "Staff training costs are cut to zero at once", "Negative reviews spread fast and damage its reputation", "An automatic fine gets issued by Trading Standards"]}'::jsonb, '{"answer": 2, "explain": "The card explains that negative reviews spread rapidly on social media, damaging reputation and pushing customers towards competitors."}'::jsonb),
('business:4-4-consumer-law:learn:fdffe293', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of Complying with Consumer Law", "reading": "<p>For a 7-mark ''evaluate'' or ''discuss'' question, you must be able to argue both sides. Complying with consumer law creates both benefits and challenges for a business.</p>\n    <div class=\"two-col\">\n      <div>\n        <div class=\"col-head\">✓ Advantages of Complying</div>\n        <div class=\"pro-item\"><strong>Improved Reputation:</strong> Consistently selling high-quality, correctly described goods builds a strong reputation, increasing customer loyalty and long-term sales revenue.</div>\n        <div class=\"pro-item\"><strong>Fewer Returns & Refunds:</strong> Producing goods of satisfactory quality reduces costly refund and return processing, directly protecting profit margins.</div>\n        <div class=\"pro-item\"><strong>Avoids Legal Action:</strong> Compliance prevents costly compensation claims and court proceedings, protecting the business financially and reputationally.</div>\n        <div class=\"pro-item\"><strong>Competitive Advantage:</strong> A business known for quality and reliability can differentiate itself from competitors and attract more customers over time.</div>\n      </div>\n      <div>\n        <div class=\"col-head\">✗ Disadvantages of Complying</div>\n        <div class=\"con-item\"><strong>Training Costs:</strong> Investing in employee training to ensure goods meet quality standards adds to operating costs, reducing short-term profits.</div>\n        <div class=\"con-item\"><strong>Higher Production Costs:</strong> Meeting quality standards may require better raw materials or upgraded equipment, raising the cost of production.</div>\n        <div class=\"con-item\"><strong>Refund & Compensation Risk:</strong> Even compliant businesses may face unexpected refund demands or compensation claims if products fail, creating unpredictable costs.</div>\n        <div class=\"con-item\"><strong>Reputational Risk Remains:</strong> Even one high-profile product failure — especially amplified on social media — can cause lasting damage despite a strong compliance record.</div>\n      </div>\n    </div>\n    <p style=\"margin-top:12px;\"><strong>Examiner Tip:</strong> When evaluating, always consider the specific business context. A large, well-established business may absorb one complaint without lasting damage — but a smaller business with a local reputation could be severely affected by a single product failure.</p>", "question": "According to the Examiner Tip, which type of business could be more severely affected by a single product failure?", "options": ["A business operating only online", "A smaller business with a local reputation", "A business with multiple product lines", "A large, well-established business"]}'::jsonb, '{"answer": 1, "explain": "The Examiner Tip states a smaller business with a local reputation could be severely affected by just one product failure, unlike a large established business."}'::jsonb),
('business:4-4-consumer-law:learn:fbb37418', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Consumer Law in the Real World", "reading": "<div class=\"case-study-box\">\n      <h4>Case Study: Primark Ltd</h4>\n      <p>Primark is one of the UK''s largest fashion retailers, selling clothing and homeware at prices significantly lower than most competitors. It launched an online click and collect service in 2022.</p>\n      <p>Being a low-cost retailer does NOT exempt Primark from the Consumer Rights Act — all products must still be of satisfactory quality, fit for purpose, and as described.</p>\n      <p><strong>Takeaway:</strong> If Primark''s low-cost products are found to be ''not as described'' or not of satisfactory quality, the business could face a large volume of returns. Since Primark operates on very thin profit margins with high sales volume, excessive refunds could significantly hurt profitability. Negative social media coverage could further damage its reputation with price-conscious shoppers.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Pukka Pies Ltd</h4>\n      <p>Pukka Pies Ltd is a family-owned business with approximately 360 employees making high-quality savoury pies, sold in over 4,000 food stores nationwide. Three of its key values — delighting customers with quality pies and building trust with suppliers through food safety — directly support its compliance with consumer law.</p>\n      <p><strong>Takeaway:</strong> For a food manufacturer, the safety of goods is especially critical. Defective food products could cause illness or injury, triggering massive compensation claims under the Consumer Protection Act 1987 and catastrophic reputational damage — far outweighing the cost of maintaining quality standards.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Which? — The Consumers'' Champion</h4>\n      <p>Which? (formerly the Consumer''s Association) was founded in 1957 and works on behalf of customers, making them aware of their legal rights and testing products for compliance with the law. It has challenged supermarkets and banks to treat customers more fairly.</p>\n      <p><strong>Takeaway:</strong> Which? exists to make individual customers as powerful as the large organisations they deal with. Its ability to publicly challenge major businesses puts significant pressure on all firms to stay within the law — reinforcing that consumer law is actively enforced, not just theoretical.</p>\n    </div>", "question": "Approximately how many employees does Pukka Pies Ltd have, according to the case study?", "options": ["1,957", "100", "4,000", "360"]}'::jsonb, '{"answer": 3, "explain": "The case study states Pukka Pies Ltd is a family-owned business with approximately 360 employees."}'::jsonb),
('business:4-4-consumer-law:misc:09b1fd1e', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Consumer law requires goods to be of the ''best possible quality''.</p><p><strong>✅ The correct idea:</strong> Consumer law only requires ''satisfactory quality'' — a standard that reflects the price paid. A budget product does not need to be as good as a luxury product; it just needs to be appropriate for its price point.</p>", "question": "What standard of quality does consumer law actually require?", "options": ["Premium quality for all goods", "No legally defined quality standard", "Satisfactory quality, reflecting the price paid", "The best possible quality regardless of price"]}'::jsonb, '{"answer": 2, "explain": "Consumer law only requires ''satisfactory quality'' — a standard appropriate to the price paid, not the best possible quality."}'::jsonb),
('business:4-4-consumer-law:misc:a0219082', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing about fair wages, worker rights, or ethical suppliers will earn marks in a consumer law question.</p><p><strong>✅ The correct idea:</strong> Consumer law is specifically about protecting customers when they buy goods and services. Employment law covers workers'' rights. Ethical sourcing is a separate topic. The 2025 examiner''s report explicitly warned that candidates who wrote about wages or working conditions scored zero — even with good application and analysis.</p>", "question": "What did the 2025 examiner''s report say about answers discussing fair wages in a consumer law question?", "options": ["They earned partial marks for application only", "They earned knowledge marks but no application marks", "They scored zero despite good application and analysis", "They earned full marks if linked to reputation"]}'::jsonb, '{"answer": 2, "explain": "The examiner''s report explicitly warned that candidates writing about wages or working conditions scored zero, despite good application and analysis."}'::jsonb),
('business:4-4-consumer-law:misc:9df257ad', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The 30-day refund rule applies to all products, including downloaded music and apps.</p><p><strong>✅ The correct idea:</strong> The 30-day return rule does NOT apply to digital products such as downloaded music, films, or apps. For digital goods, customers can request a replacement or a price reduction of up to 100%.</p>", "question": "Does the 30-day full refund rule apply to downloaded music or apps?", "options": ["Yes — it applies to all products including digital ones", "Only to downloaded films, not music or apps", "No — digital products are excluded from this rule", "Only if the digital product cost over £50"]}'::jsonb, '{"answer": 2, "explain": "The 30-day rule does not apply to digital products; customers can instead request a replacement or a price reduction of up to 100%."}'::jsonb),
('business:4-4-consumer-law:misc:c492686e', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> After 30 days, customers have no rights at all and cannot make any further claims for faulty goods.</p><p><strong>✅ The correct idea:</strong> Customer rights continue beyond 30 days. Within 6 months, customers can claim a repair or replacement. After 6 months, they can still claim for up to six years if they can prove the fault existed at the time of purchase.</p>", "question": "What can a customer do after 30 days but within 6 months if goods turn out to be faulty?", "options": ["Only claim a full refund", "Only complain to Which? magazine", "Claim a repair or replacement", "Nothing — rights end completely after 30 days"]}'::jsonb, '{"answer": 2, "explain": "Within 6 months of purchase, customers can still claim a repair or replacement, as the fault is assumed to have existed at purchase."}'::jsonb),
('business:4-4-consumer-law:misc:b7870f0b', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Complying with consumer law is purely a cost to a business with no benefits.</p><p><strong>✅ The correct idea:</strong> Compliance brings significant benefits: improved reputation, fewer returns, increased customer loyalty, and avoidance of costly legal action. In 7-mark questions, you must evaluate both sides — benefits and drawbacks.</p>", "question": "What benefit does complying with consumer law bring to a business, according to this card?", "options": ["Automatic increase in market share", "Guaranteed exemption from all future legal claims", "Immediate elimination of production costs", "Improved reputation and increased customer loyalty"]}'::jsonb, '{"answer": 3, "explain": "Compliance brings benefits such as improved reputation, fewer returns, increased customer loyalty, and avoidance of costly legal action."}'::jsonb),
('business:4-4-consumer-law:misc:4b32c90f', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Consumer law only applies to large businesses with many customers.</p><p><strong>✅ The correct idea:</strong> Consumer law applies to ALL businesses selling goods or services to customers, regardless of size. A small family-run bakery must comply with the same Consumer Rights Act 2015 as a large supermarket like Tesco.</p>", "question": "Does consumer law apply only to large businesses with many customers?", "options": ["Yes — only businesses with over 100 employees", "No — only businesses that sell online", "No — it applies to businesses of any size", "Yes — only publicly listed companies"]}'::jsonb, '{"answer": 2, "explain": "Consumer law applies to all businesses selling goods or services, including a small family-run bakery, just as much as a large supermarket like Tesco."}'::jsonb),
('business:4-4-consumer-law:misc:005bbd49', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The Consumer Rights Act 2015 and the Consumer Protection Act 1987 are the same law.</p><p><strong>✅ The correct idea:</strong> These are two separate laws. The Consumer Rights Act 2015 covers the three requirements (satisfactory quality, fit for purpose, as described). The Consumer Protection Act 1987 specifically covers compensation claims when defective products cause death, injury, or damage.</p>", "question": "What is the key difference between the Consumer Rights Act 2015 and the Consumer Protection Act 1987?", "options": ["The 1987 Act only protects customers of food businesses", "The 2015 Act covers quality; the 1987 Act covers compensation", "The 2015 Act only protects buyers of digital products", "The two Acts are actually the same law with different names"]}'::jsonb, '{"answer": 1, "explain": "The two laws are separate: the 2015 Act covers satisfactory quality, fit for purpose and as described, while the 1987 Act covers compensation for death, injury, or damage caused by defective products."}'::jsonb)
